import { assignInlineVars } from '@vanilla-extract/dynamic';
import { useMemo } from 'react';

import { useValueContainerDisplayText } from './use-value-container-display-state.js';
import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import {
  DEFAULT_SERIES_NAME_LINES,
  MAX_SERIES_NAME_LINES,
  SYMBOL_AND_SPACING_WIDTH,
} from '../../../constants.js';
import { useExternalConfig } from '../../../contexts/ExternalConfigContext.js';
import { seriesNameMaxLinesVar } from '../../../tooltip.sty.js';
import { InternalSeriesItemProps } from '../../../types/series.js';
import { calculateTotalWidth400 } from '../../../utils/width-calculation.js';
import { formatSeriesNameForDisplay } from '../utils/format-series-name-for-display.js';
import { getDisplayNameText } from '../utils/get-display-name-text.js';
import { getDisplayText } from '../utils/get-display-text.js';
import { getIsTruncated } from '../utils/get-is-truncated.js';
import { getNameTextStyle } from '../utils/get-name-text-style.js';

const resolveDisplayText = (
  text: string,
  shouldUseMultiLineCss: boolean,
  availableWidth: number | undefined,
  validatedMaxLines: number,
  truncationMode: TruncationMode,
): string => {
  if (shouldUseMultiLineCss) {
    if (truncationMode === 'end') {
      return text;
    }
    const wrapWidth =
      availableWidth !== undefined
        ? availableWidth * validatedMaxLines
        : undefined;
    return getDisplayText(text, wrapWidth, truncationMode) || '';
  }
  return getDisplayText(text, availableWidth, truncationMode) || '';
};

const calculateAvailableNameWidth = (
  maxWidth: number,
  actualValueWidth: number,
): number | undefined => {
  if (!maxWidth) {
    return undefined;
  }
  const valueOffset = actualValueWidth > 0 ? actualValueWidth + 6 : 0;
  return maxWidth - valueOffset - SYMBOL_AND_SPACING_WIDTH;
};

const calculateNameText = (
  name: string | string[],
  multiLine: boolean,
  shouldUseMultiLineCss: boolean,
  availableNameWidth: number | undefined,
  truncationMode: TruncationMode,
  validatedMaxLines: number,
): string | string[] => {
  if (Array.isArray(name)) {
    if (multiLine) {
      return name.map((item) =>
        resolveDisplayText(
          item,
          shouldUseMultiLineCss,
          availableNameWidth,
          validatedMaxLines,
          truncationMode,
        ),
      );
    }
    return formatSeriesNameForDisplay(name);
  }

  return resolveDisplayText(
    name,
    shouldUseMultiLineCss,
    availableNameWidth,
    validatedMaxLines,
    truncationMode,
  );
};

export const useSeriesItemDisplayState = (
  props: InternalSeriesItemProps & { maxWidth: number },
) => {
  const {
    name,
    description,
    value,
    valueUnit,
    relativeValue,
    relativeValueUnit,
    maxWidth,

    maxLines = DEFAULT_SERIES_NAME_LINES,
    multiLine = false,
  } = props;
  const { truncationMode } = useExternalConfig();
  const validatedMaxLines = Math.min(maxLines, MAX_SERIES_NAME_LINES);
  const isSingleLine = validatedMaxLines === 1;
  const isTruncationEnd = truncationMode === 'end';

  const {
    displayValueText,
    displayRelativeValueText,
    actualValueWidth,
    fullValueText,
    fullRelativeValueText,
  } = useValueContainerDisplayText(
    value?.toString(),
    valueUnit,
    relativeValue,
    relativeValueUnit,
    maxWidth,
    truncationMode,
  );

  const availableNameWidth = calculateAvailableNameWidth(
    maxWidth,
    actualValueWidth,
  );

  const shouldUseMultiLineCss = !isSingleLine;

  const nameText = calculateNameText(
    name,
    multiLine,
    shouldUseMultiLineCss,
    availableNameWidth,
    truncationMode,
    validatedMaxLines,
  );

  const multiLineMode: 'clamp' | 'wrap' =
    shouldUseMultiLineCss && truncationMode !== 'end' ? 'wrap' : 'clamp';

  const displayNameText = getDisplayNameText(name, multiLine);

  const totalTextWidth = useMemo(() => {
    return Array.isArray(displayNameText)
      ? calculateTotalWidth400(...displayNameText)
      : calculateTotalWidth400(displayNameText);
  }, [displayNameText]);

  const isMultiLineCssClamped =
    isTruncationEnd &&
    shouldUseMultiLineCss &&
    !!availableNameWidth &&
    Math.ceil(totalTextWidth / availableNameWidth) > validatedMaxLines;

  const isTruncated = getIsTruncated(
    isMultiLineCssClamped,
    name,
    multiLine,
    nameText,
    displayNameText,
  );

  const nameTextStyle = getNameTextStyle(
    isSingleLine,
    multiLine,
    multiLineMode,
  );
  const nameStyle = shouldUseMultiLineCss
    ? assignInlineVars({ [seriesNameMaxLinesVar]: String(validatedMaxLines) })
    : {};

  const descriptionText =
    typeof description === 'string' && description.length > 0
      ? resolveDisplayText(
          description,
          shouldUseMultiLineCss,
          availableNameWidth,
          validatedMaxLines,
          truncationMode,
        )
      : undefined;

  const isDescriptionTruncated =
    typeof description === 'string' && descriptionText !== description;

  return {
    nameText,
    displayNameText,
    descriptionText,
    fullDescriptionText: description,
    isDescriptionTruncated,
    descriptionShouldUseMultiLineCss: shouldUseMultiLineCss,
    descriptionMultiLineMode: multiLineMode,
    displayValueText,
    displayRelativeValueText,
    fullValueText,
    fullRelativeValueText,
    shouldUseMultiLineCss,
    nameTextStyle,
    nameStyle,
    isTruncated,
    actualValueWidth,
  };
};
